using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change #1 — Discriminator property renamed from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator", so we must preserve the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change #2 — id format changed from "Product|123" to "123".
            // Existing documents use "Product|123", so we must preserve the old format.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id")
                .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change #3 — HasIndex() now throws for Cosmos provider.
            // Cosmos manages indexes server-side via indexing policy; remove the EF index.
            // (HasIndex call removed)
        });
    }
}

