 using Microsoft.EntityFrameworkCore;
 using Microsoft.EntityFrameworkCore.ChangeTracking;
 using Microsoft.EntityFrameworkCore.ValueGeneration;

 class ProductContext : DbContext
 {
     public DbSet<Product> Products => Set<Product>();
     protected override void OnModelCreating(ModelBuilder modelBuilder)
     {
         modelBuilder.Entity<Product>(entity =>
         {
             entity.ToContainer("Products");

             // BREAKING CHANGE #1 — Discriminator property renamed from "Discriminator" to "$type".
             // Existing 500K documents use "Discriminator", so preserve the old name.
             entity.HasDiscriminator<string>("Discriminator");

             // BREAKING CHANGE #2 — id synthesis changed from "Product|{key}" to just "{key}".
             // Existing documents use "Product|123" format, so preserve the old id format
             // by mapping a shadow property with a value generator.
             entity.Property<string>("__id")
                 .ToJsonProperty("id")
                 .HasValueGenerator<LegacyCosmosIdGenerator>();

             // BREAKING CHANGE #3 — HasIndex() now throws for Cosmos provider.
             // Cosmos manages its own indexes via indexing policy; EF HasIndex removed.
         });
     }
 }

 /// <summary>
 /// Reproduces the EF Core 8 id format ("Product|{key}") so EF Core 9 can
 /// read/write documents that were created under the old convention.
 /// </summary>
 class LegacyCosmosIdGenerator : ValueGenerator<string>
 {
     public override bool GeneratesTemporaryValues => false;
     public override string Next(EntityEntry entry)
         => $"Product|{entry.Property("Id").CurrentValue}";
 }

 class Product { public int Id { get; set; } public string Sku { get; set; } }

